'use client';

import { useState } from 'react';
import {
  AchievementCard,
  Badge,
  PageHeader,
  ProfileHero,
  Tabs,
} from '../../components/ui';
import {
  AccountPanel,
  AppearancePanel,
  NotificationsPanel,
  ProfileDetailsPanel,
} from './panels';
import { activeMockUser, canView, mockProfileAchievements, siteContent } from '../../mocks';
import styles from './page.module.scss';

export default function ProfilePage() {
  const [tab, setTab] = useState<
    'profile' | 'notifications' | 'appearance' | 'account'
  >('profile');
  const [saved, setSaved] = useState(false);
  const [form, setForm] = useState({
    name: activeMockUser.fullName,
    email: activeMockUser.email,
    phone: '+380 67 123 4567',
    timezone: 'Europe/Kiev',
    nativeLanguage: 'Ukrainian',
    targetLevel: 'C1',
    weeklyGoal: '5',
    bio: 'Full-stack developer learning English for professional growth and international opportunities.',
  });
  const [notifications, setNotifications] = useState({
    lessonReminder: true,
    streakAlert: true,
    weeklyReport: true,
    newVocab: false,
    teacherMessages: true,
  });
  const [theme, setTheme] = useState<'light' | 'dark' | 'auto'>('light');

  const achievements = mockProfileAchievements;
  if (!canView('profile', activeMockUser.role)) return null;

  return (
    <div className={`${styles.page} container container--page`}>
      <PageHeader
        className={styles.pageHeader}
        titleClassName={styles.pageTitle}
        subtitleClassName={styles.pageSub}
        title={siteContent.profile.title}
        subtitle={`${siteContent.profile.subtitle} · ${activeMockUser.role}`}
      />

      <ProfileHero
        className={styles.profileHero}
        avatarClassName={styles.avatarBig}
        infoClassName={styles.heroInfo}
        nameClassName={styles.heroName}
        metaClassName={styles.heroMeta}
        badgesClassName={styles.heroBadges}
        statsClassName={styles.heroStats}
        statClassName={styles.heroStat}
        statValueClassName={styles.heroStatVal}
        statLabelClassName={styles.heroStatLbl}
        avatar={activeMockUser.avatarInitials}
        name={form.name}
        meta={`${activeMockUser.targetLevel} · ${activeMockUser.role}`}
        badges={
          <>
            <Badge className={styles.badge}>Upper-Intermediate</Badge>
            <Badge
              className={`${styles.badge} ${styles.badgeGreen}`}
              variant="green"
            >
              Active learner
            </Badge>
          </>
        }
        stats={[
          { value: '847', label: 'Words' },
          { value: '38', label: 'Lessons' },
          { value: '14', label: 'Streak' },
        ]}
      />

      <div className={styles.achievementsRow}>
        {achievements.map((achievement) => (
          <AchievementCard
            key={achievement.label}
            icon={achievement.icon}
            label={achievement.label}
            unlocked={achievement.unlocked}
            className={styles.achievement}
            unlockedClassName={styles.achievementUnlocked}
            lockedClassName={styles.achievementLocked}
            iconClassName={styles.achievementIcon}
            labelClassName={styles.achievementLabel}
          />
        ))}
      </div>

      <Tabs
        value={tab}
        onValueChange={setTab}
        ariaLabel="Profile settings tabs"
        listClassName={styles.tabsRow}
        triggerClassName={styles.tabBtn}
        activeTriggerClassName={styles.tabActive}
        panelClassName={styles.tabContent}
        items={[
          {
            value: 'profile',
            label: 'Profile',
            panel: (
              <ProfileDetailsPanel
                form={form}
                setForm={setForm}
                saved={saved}
                onSave={() => {
                  setSaved(true);
                  setTimeout(() => setSaved(false), 2500);
                }}
              />
            ),
          },
          {
            value: 'notifications',
            label: 'Notifications',
            panel: (
              <NotificationsPanel
                notifications={notifications}
                setNotifications={setNotifications}
              />
            ),
          },
          {
            value: 'appearance',
            label: 'Appearance',
            panel: <AppearancePanel theme={theme} setTheme={setTheme} />,
          },
          {
            value: 'account',
            label: 'Account',
            panel: <AccountPanel />,
          },
        ]}
      />
    </div>
  );
}
